   491→
   492→func (c *Controller) syncCheckStates(
   493→	ctx context.Context, wl *kueue.Workload,
   494→	wlInfo *workloadInfo,
   495→	checkConfig map[kueue.AdmissionCheckReference]*kueue.ProvisioningRequestConfig,
   496→	activeOrLastPRForChecks map[kueue.AdmissionCheckReference]*autoscaling.ProvisioningRequest,
   497→) error {
   498→	log := ctrl.LoggerFrom(ctx)
   499→	wlInfo.update(wl, c.clock)
   500→	checksMap := slices.ToRefMap(wl.Status.AdmissionChecks, func(c *kueue.AdmissionCheckState) kueue.AdmissionCheckReference { return c.Name })
   501→	wlPatch := workload.BaseSSAWorkload(wl, true)
   502→	wlPatch.Status.RequeueState = wl.Status.RequeueState.DeepCopy()
   503→	recorderMessages := make([]string, 0, len(checkConfig))
   504→	updated := false
   505→	for check, prc := range checkConfig {
   506→		checkState := *checksMap[check]
   507→		//nolint:gocritic // ignore ifElseChain
   508→		if prc == nil {
   509→			// the check is not active
   510→			updated = updateCheckState(&checkState, kueue.CheckStatePending) || updated
   511→			updated = updateCheckMessage(&checkState, CheckInactiveMessage) || updated
   512→		} else if !c.reqIsNeeded(wl, prc) {
   513→			if updateCheckState(&checkState, kueue.CheckStateReady) {
   514→				updated = true
   515→				checkState.Message = NoRequestNeeded
   516→				checkState.PodSetUpdates = nil
   517→			}
   518→		} else {
   519→			pr := activeOrLastPRForChecks[check]
   520→			if pr == nil {
   521→				return nil
   522→			}
   523→			log.V(3).Info("Synchronizing admission check state based on provisioning request", "wl", klog.KObj(wl),
   524→				"check", check,
   525→				"prName", pr.Name,
   526→				"failed", isFailed(pr),
   527→				"provisioned", isProvisioned(pr),
   528→				"accepted", isAccepted(pr),
   529→				"bookingExpired", isBookingExpired(pr),
   530→				"capacityRevoked", isCapacityRevoked(pr))
   531→			backoffBaseSeconds := *prc.Spec.RetryStrategy.BackoffBaseSeconds
   532→			backoffMaxSeconds := *prc.Spec.RetryStrategy.BackoffMaxSeconds
   533→			backoffLimitCount := *prc.Spec.RetryStrategy.BackoffLimitCount
   534→			switch {
   535→			case isFailed(pr):
   536→				if attempt := getAttempt(log, pr, wl.Name, check); attempt <= backoffLimitCount {
   537→					// it is going to be retried
   538→					message := fmt.Sprintf("Retrying after failure: %s", apimeta.FindStatusCondition(pr.Status.Conditions, autoscaling.Failed).Message)
   539→					updated = updateCheckMessage(&checkState, message) || updated
   540→					if wl.Status.RequeueState == nil || getAttempt(log, pr, wl.Name, check) > ptr.Deref(wl.Status.RequeueState.Count, 0) {
   541→						// We don't want to Retry on old ProvisioningRequests
   542→						updated = true
   543→						updateCheckState(&checkState, kueue.CheckStateRetry)
   544→						workload.UpdateRequeueState(wlPatch, backoffBaseSeconds, backoffMaxSeconds, c.clock)
   545→					}
   546→				} else {
   547→					updated = true
   548→					checkState.State = kueue.CheckStateRejected
   549→					checkState.Message = apimeta.FindStatusCondition(pr.Status.Conditions, autoscaling.Failed).Message
   550→				}
   551→			case isCapacityRevoked(pr):
   552→				if workload.IsActive(wl) && !workload.IsFinished(wl) {
   553→					// We mark the admission check as rejected to trigger workload deactivation.
   554→					// This is needed to prevent replacement pods being stuck in the pending phase indefinitely
   555→					// as the nodes are already deleted by Cluster Autoscaler.
   556→					updated = updateCheckState(&checkState, kueue.CheckStateRejected) || updated
   557→					updated = updateCheckMessage(&checkState, apimeta.FindStatusCondition(pr.Status.Conditions, autoscaling.CapacityRevoked).Message) || updated
   558→				}
   559→			case isBookingExpired(pr):
   560→				if !workload.IsAdmitted(wl) {
   561→					if attempt := getAttempt(log, pr, wl.Name, check); attempt <= backoffLimitCount {
   562→						// it is going to be retried
   563→						message := fmt.Sprintf("Retrying after booking expired: %s", apimeta.FindStatusCondition(pr.Status.Conditions, autoscaling.BookingExpired).Message)
   564→						updated = updateCheckMessage(&checkState, message) || updated
   565→						if wl.Status.RequeueState == nil || getAttempt(log, pr, wl.Name, check) > ptr.Deref(wl.Status.RequeueState.Count, 0) {
   566→							updated = true
   567→							updateCheckState(&checkState, kueue.CheckStateRetry)
   568→							workload.UpdateRequeueState(wlPatch, backoffBaseSeconds, backoffMaxSeconds, c.clock)
   569→						}
   570→					} else {
   571→						updated = true
   572→						checkState.State = kueue.CheckStateRejected
   573→						checkState.Message = apimeta.FindStatusCondition(pr.Status.Conditions, autoscaling.BookingExpired).Message
   574→					}
   575→				}
   576→			case isProvisioned(pr):
   577→				if updateCheckState(&checkState, kueue.CheckStateReady) {
   578→					updated = true
   579→					// add the pod podSetUpdates
   580→					checkState.PodSetUpdates = podSetUpdates(log, wl, pr, prc)
   581→					// propagate the message from the provisioning request status into the workload
   582→					// to change to the "successfully provisioned" message after provisioning
   583→					updateCheckMessage(&checkState, apimeta.FindStatusCondition(pr.Status.Conditions, autoscaling.Provisioned).Message)
   584→				}
   585→			case isAccepted(pr):
   586→				if provisionedCond := apimeta.FindStatusCondition(pr.Status.Conditions, autoscaling.Provisioned); provisionedCond != nil {
   587→					// propagate the ETA update from the provisioning request into the workload
   588→					updated = updateCheckMessage(&checkState, provisionedCond.Message) || updated
   589→					updated = updateCheckState(&checkState, kueue.CheckStatePending) || updated
   590→				}
   591→			default:
   592→				updated = updateCheckState(&checkState, kueue.CheckStatePending) || updated
   593→			}
   594→		}
   595→
   596→		existingCondition := workload.FindAdmissionCheck(wlPatch.Status.AdmissionChecks, checkState.Name)
   597→		if existingCondition != nil && existingCondition.State != checkState.State {
   598→			message := fmt.Sprintf("Admission check %s updated state from %s to %s", checkState.Name, existingCondition.State, checkState.State)
   599→			if checkState.Message != "" {
   600→				message += fmt.Sprintf(" with message %s", checkState.Message)
   601→			}
   602→			recorderMessages = append(recorderMessages, message)
   603→		}
   604→		workload.SetAdmissionCheckState(&wlPatch.Status.AdmissionChecks, checkState, c.clock)
   605→	}
   606→	if updated {
   607→		if err := c.client.Status().Patch(ctx, wlPatch, client.Apply, client.FieldOwner(kueue.ProvisioningRequestControllerName), client.ForceOwnership); err != nil {
   608→			return err
   609→		}
   610→		for i := range recorderMessages {
   611→			c.record.Event(wl, corev1.EventTypeNormal, "AdmissionCheckUpdated", api.TruncateEventMessage(recorderMessages[i]))
   612→		}
   613→	}
   614→	wlInfo.update(wlPatch, c.clock)
   615→	return nil
   616→}
