   726→
   727→func (p *prcHandler) Create(ctx context.Context, event event.CreateEvent, q workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   728→	prc, isPRC := event.Object.(*kueue.ProvisioningRequestConfig)
   729→	if !isPRC {
   730→		return
   731→	}
   732→	err := p.reconcileWorkloadsUsing(ctx, prc.Name, q)
   733→	if err != nil {
   734→		ctrl.LoggerFrom(ctx).V(5).Error(err, "Failure on create event", "provisioningRequestConfig", klog.KObj(prc))
   735→	}
   736→}
   737→
   738→func (p *prcHandler) Update(ctx context.Context, event event.UpdateEvent, q workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   739→	oldPRC, isOldPRC := event.ObjectOld.(*kueue.ProvisioningRequestConfig)
   740→	newPRC, isNewPRC := event.ObjectNew.(*kueue.ProvisioningRequestConfig)
   741→	if !isNewPRC || !isOldPRC {
   742→		return
   743→	}
   744→
   745→	if oldPRC.Spec.ProvisioningClassName != newPRC.Spec.ProvisioningClassName || !maps.Equal(oldPRC.Spec.Parameters, newPRC.Spec.Parameters) || !slices.CmpNoOrder(oldPRC.Spec.ManagedResources, newPRC.Spec.ManagedResources) {
   746→		err := p.reconcileWorkloadsUsing(ctx, oldPRC.Name, q)
   747→		if err != nil {
   748→			ctrl.LoggerFrom(ctx).V(5).Error(err, "Failure on update event", "provisioningRequestConfig", klog.KObj(oldPRC))
   749→		}
   750→	}
   751→}
