   753→func (p *prcHandler) Delete(ctx context.Context, event event.DeleteEvent, q workqueue.TypedRateLimitingInterface[reconcile.Request]) {
   754→	prc, isPRC := event.Object.(*kueue.ProvisioningRequestConfig)
   755→	if !isPRC {
   756→		return
   757→	}
   758→	err := p.reconcileWorkloadsUsing(ctx, prc.Name, q)
   759→	if err != nil {
   760→		ctrl.LoggerFrom(ctx).V(5).Error(err, "Failure on delete event", "provisioningRequestConfig", klog.KObj(prc))
   761→	}
   762→}
