   791→func (c *Controller) SetupWithManager(mgr ctrl.Manager) error {
   792→	ach := &acHandler{
   793→		client: c.client,
   794→	}
   795→	prch := &prcHandler{
   796→		client:            c.client,
   797→		acHandlerOverride: ach.reconcileWorkloadsUsing,
   798→	}
   799→	err := ctrl.NewControllerManagedBy(mgr).
   800→		Named("provisioning_workload").
   801→		For(&kueue.Workload{}).
   802→		Owns(&autoscaling.ProvisioningRequest{}).
   803→		Watches(&kueue.AdmissionCheck{}, ach).
   804→		Watches(&kueue.ProvisioningRequestConfig{}, prch).
   805→		Complete(c)
   806→	if err != nil {
   807→		return err
   808→	}
   809→
   810→	prcACh := &prcHandler{
   811→		client: c.client,
   812→	}
   813→	acReconciler := &acReconciler{
   814→		client: c.client,
   815→		helper: c.helper,
   816→	}
   817→
   818→	return ctrl.NewControllerManagedBy(mgr).
   819→		Named("provisioning_admissioncheck").
   820→		For(&kueue.AdmissionCheck{}).
   821→		Watches(&kueue.ProvisioningRequestConfig{}, prcACh).
   822→		Complete(acReconciler)
   823→}
