   825→func limitObjectName(fullName string) string {
   826→	if len(fullName) <= objNameMaxPrefixLength {
   827→		return fullName
   828→	}
   829→	h := sha1.New()
   830→	h.Write([]byte(fullName))
   831→	hashBytes := hex.EncodeToString(h.Sum(nil))
   832→	return fmt.Sprintf("%s-%s", fullName[:objNameMaxPrefixLength], hashBytes[:objNameHashLength])
   833→}
