   842→func mergePodSets(
   843→	wl *kueue.Workload,
   844→	prcSpec *kueue.ProvisioningRequestConfigSpec,
   845→) ([]MergedPodSet, error) {
   846→	expectedPodSets := requiredPodSets(wl.Spec.PodSets, prcSpec.ManagedResources)
   847→	psaMap := slices.ToRefMap(wl.Status.Admission.PodSetAssignments, func(p *kueue.PodSetAssignment) kueue.PodSetReference { return p.Name })
   848→	podSetMap := slices.ToRefMap(wl.Spec.PodSets, func(ps *kueue.PodSet) kueue.PodSetReference { return ps.Name })
   849→
   850→	mergePolicy := prcSpec.PodSetMergePolicy
   851→	mergedPodSets := []MergedPodSet{}
   852→	for _, psName := range expectedPodSets {
   853→		ps, psFound := podSetMap[psName]
   854→		psa, psaFound := psaMap[psName]
   855→		if !psFound || !psaFound {
   856→			return nil, errInconsistentPodSetAssignments
   857→		}
   858→
   859→		merged := false
   860→		if mergePolicy != nil {
   861→			for i, mps := range mergedPodSets {
   862→				if merged = canMergePodSets(mps.PodSet, ps, mergePolicy); merged {
   863→					mergedPodSets[i].Count += ptr.Deref(psa.Count, ps.Count)
   864→					break
   865→				}
   866→			}
   867→		}
   868→
   869→		if !merged {
   870→			mergedPodSets = append(mergedPodSets, MergedPodSet{
   871→				Name:             psName,
   872→				PodSet:           ps,
   873→				PodSetAssignment: psa,
   874→				Count:            ptr.Deref(psa.Count, ps.Count),
   875→			})
   876→		}
   877→	}
   878→
   879→	return mergedPodSets, nil
   880→}
   881→
   882→func canMergePodSets(ps1, ps2 *kueue.PodSet, mergePolicy *kueue.ProvisioningRequestConfigPodSetMergePolicy) bool {
   883→	switch *mergePolicy {
   884→	case kueue.IdenticalPodTemplates:
   885→		return equality.Semantic.DeepEqual(ps1.Template, ps2.Template)
   886→	case kueue.IdenticalWorkloadSchedulingRequirements:
   887→		return arePodSetsSimilar(ps1, ps2)
   888→	default:
   889→		return false
   890→	}
   891→}
   892→
   893→func arePodSetsSimilar(ps1, ps2 *kueue.PodSet) bool {
   894→	return areContainersEqual(ps1.Template.Spec.Containers, ps2.Template.Spec.Containers) &&
   895→		areContainersEqual(ps1.Template.Spec.InitContainers, ps2.Template.Spec.InitContainers) &&
   896→		equality.Semantic.DeepEqual(ps1.Template.Spec.Resources, ps2.Template.Spec.Resources) &&
   897→		equality.Semantic.DeepEqual(ps1.Template.Spec.NodeSelector, ps2.Template.Spec.NodeSelector) &&
   898→		equality.Semantic.DeepEqual(ps1.Template.Spec.Tolerations, ps2.Template.Spec.Tolerations) &&
   899→		equality.Semantic.DeepEqual(ps1.Template.Spec.Affinity, ps2.Template.Spec.Affinity) &&
   900→		equality.Semantic.DeepEqual(ps1.Template.Spec.ResourceClaims, ps2.Template.Spec.ResourceClaims)
   901→}
   902→
   903→// areContainersEqual compares the resource requests of containers between two lists of PodSet containers.
   904→func areContainersEqual(ps1Containers []corev1.Container, ps2Containers []corev1.Container) bool {
   905→	if len(ps1Containers) != len(ps2Containers) {
   906→		return false
   907→	}
   908→	for i := range ps1Containers {
   909→		if !equality.Semantic.DeepEqual(ps1Containers[i].Resources.Requests, ps2Containers[i].Resources.Requests) {
   910→			return false
   911→		}
   912→	}
   913→	return true
   914→}
   915→

