)

// TestDeprecatedAnnotationsNotUsed verifies that deprecated annotations are not used
func TestDeprecatedAnnotationsNotUsed(t *testing.T) {
	// Create a mock workload and provisioning request
	wl := &kueue.Workload{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-workload",
			Namespace: "default",
		},
		Spec: kueue.WorkloadSpec{
			PodSets: []kueue.PodSet{
				{
					Name:  "main",
					Count: 1,
					Template: corev1.PodTemplateSpec{
						Spec: corev1.PodSpec{
							Containers: []corev1.Container{
								{
									Name:  "container",
									Image: "test:latest",
									Resources: corev1.ResourceRequirements{
										Requests: corev1.ResourceList{
											corev1.ResourceCPU: *ptr.To[resource.Quantity](resource.MustParse("1")),
										},
									},
								},
							},
						},
					},
				},
			},
		},
		Status: kueue.WorkloadStatus{
			Admission: &kueue.Admission{
				PodSetAssignments: []kueue.PodSetAssignment{
					{
						Name:  "main",
						Count: ptr.To[int32](1),
					},
				},
			},
		},
	}

	pr := &autoscaling.ProvisioningRequest{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-pr",
			Namespace: "default",
		},
		Spec: autoscaling.ProvisioningRequestSpec{
			ProvisioningClassName: "test-class",
		},
	}

	prc := &kueue.ProvisioningRequestConfig{
		Spec: kueue.ProvisioningRequestConfigSpec{
			ProvisioningClassName: "test-class",
		},
	}

	// Create a fake logger
	ctx := context.Background()
	log := logr.Discard()

	// Call podSetUpdates function to generate the annotations
	updates := provisioning.podSetUpdates(log, wl, pr, prc)

	// Check that deprecated annotations are NOT present
	for _, update := range updates {
		if _, hasDeprecatedConsumes := update.Annotations[provisioning.DeprecatedConsumesAnnotationKey]; hasDeprecatedConsumes {
			t.Errorf("Expected deprecated annotation %s to NOT be present, but it was found", provisioning.DeprecatedConsumesAnnotationKey)
		}
		if _, hasDeprecatedClassName := update.Annotations[provisioning.DeprecatedClassNameAnnotationKey]; hasDeprecatedClassName {
			t.Errorf("Expected deprecated annotation %s to NOT be present, but it was found", provisioning.DeprecatedClassNameAnnotationKey)
		}

		// Check that new annotations ARE present
		if _, hasConsumes := update.Annotations[provisioning.ConsumesAnnotationKey]; !hasConsumes {
			t.Errorf("Expected annotation %s to be present, but it was not found", provisioning.ConsumesAnnotationKey)
		}
		if _, hasClassName := update.Annotations[provisioning.ClassNameAnnotationKey]; !hasClassName {
			t.Errorf("Expected annotation %s to be present, but it was not found", provisioning.ClassNameAnnotationKey)
		}
	}
}

func main() {
	t := &testing.T{}
	TestDeprecatedAnnotationsNotUsed(t)
	if t.Failed() {
		fmt.Println("Test FAILED: Deprecated annotations are still being used")
		os.Exit(1)
	}
	fmt.Println("Test PASSED: Deprecated annotations are not used")
}

